mapper.update:
UPDATE ntc_notice
SET title = #{title},
content = #{content},
is_top = #{isTop},
status = #{status}
WHERE id = #{id}

mapper.select:
SELECT id, title, CASE WHEN LENGTH(content) > 100 THEN CONTENT(LEFT(content, 100), '...') ELSE content END AS content, publisher_id, is_top, status, create_time, update_time FROM ntc_notice WHERE status = 1
AND (title) LIKE CONCAT('%', #{keyword}, '%') OR content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY is_top DESC, create_time DESC LIMIT #{offset}, #{limit}
